fun solve(points: Array<Array<Long>>): Long {
    val n = points.size
    var count = 0L

    for (i in 0 until n) {
        for (j in 0 until n) {
            if (i == j) continue
            val x1 = points[i][0]
            val y1 = points[i][1]
            val x2 = points[j][0]
            val y2 = points[j][1]

            var slope: Double
            if (x1 == x2) {
                slope = Double.NaN
            } else {
                slope = (y2 - y1).toDouble() / (x2 - x1)
            }

            val slopeHash = mutableMapOf<Double to Long>()
            slopeHash[slope] = slopeHash[slope] ?: 0L + 1

            count += slopeHash[slope] - 1
        }
    }

